import React from 'react';

const leaderProfiles = [
  { 
    desc: 'Driving the vision for Hudson, Mayank combines deep IT consultancy with strategic manpower leadership. His focus is on pioneering industry-specific tech and sourcing.Driving the vision for Hudson, Mayank combines deep IT consultancy with strategic manpower leadership. His focus is on pioneering industry-specific tech and sourcing.Driving the vision for Hudson, Mayank combines deep IT consultancy with strategic manpower leadership. His focus is on pioneering industry-specific tech and sourcing.',
  },
  { 
    desc: 'Overseeing all software architecture and delivery, Vikas ensures that IT solutions integrate flawlessly with sector requirements. Expert in scalable systems.',
  },
];

const Electronics = () => {
  return (

    <section className="py-24 bg-white px-4 border-y border-gray-100">
        <div className="pt-24 min-h-screen bg-gray-50 p-10">
    <h1 className="text-4xl font-bold text-gray-800 border-b-4 border-yellow-500 inline-block mb-6">Electrical Solutions</h1>
    <p className="text-gray-600 text-lg">Expert staffing for power grids, industrial wiring, and renewable energy projects.</p>
  </div>
        <div className="max-w-6xl mx-auto px-4 mb-12">
        <div className="bg-orange-50 rounded-[2rem] p-8 md:p-12 text-center border border-orange-100">
          <h1 className="text-3xl md:text-4xl font-black text-gray-900 mb-3 tracking-tighter">
            Start Your Career With Us
          </h1>
          <p className="text-gray-600 mb-6 max-w-xl mx-auto">
            Join our global team and work on industry-leading electronics projects.
          </p>
          <button className="bg-orange-600 text-white px-8 py-3.5 rounded-full font-bold hover:bg-orange-700 shadow-lg shadow-orange-100 transition-all">
            View Current Openings
          </button>
        </div>
      </div>
      <div className="max-w-6xl mx-auto">
        <div className="space-y-16 max-w-5xl mx-auto">
          {leaderProfiles.map((leader, index) => (
            <div key={index} className="relative flex flex-col md:flex-row items-center bg-gray-50 border border-gray-100 p-12 rounded-[2rem] gap-10 hover:shadow-xl transition-all">
              {/* Leader image placeholder - circular placeholder in center from image */}
              <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 h-4 w-4 bg-orange-100 rounded-full"></div>

              <div className="flex-shrink-0 bg-white border border-[#E9ECEF] h-40 w-40 rounded-full flex items-center justify-center text-6xl text-orange-500 shadow-inner overflow-hidden">
                {/* Circular image placeholder lines */}
                {leader.iconPlaceholder}
              </div>

              <div className="flex-grow">
                <p className="text-[#424C5B] text-base leading-relaxed max-w-2xl">
                  {leader.desc}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Electronics;
